import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import LoginModal from './LoginModal';
import logoWhiteImage from '../assets/images/logo1.png';

const Header = ({ onLoginClick }) => {
    const { t, i18n } = useTranslation();
    const [menuOpen, setMenuOpen] = useState(false);
    const [scrolled, setScrolled] = useState(false);
    const [dropdownOpen, setDropdownOpen] = useState('');
    const [isLoginModalOpen, setIsLoginModalOpen] = useState(false);
    const [hoveredItem, setHoveredItem] = useState(null);

    const location = useLocation();

    // Close mobile menu when route changes
    useEffect(() => {
        setMenuOpen(false);
        setDropdownOpen('');
    }, [location]);

    // Add scroll listener for header style change
    useEffect(() => {
        const handleScroll = () => {
            const isScrolled = window.scrollY > 50;
            if (isScrolled !== scrolled) {
                setScrolled(isScrolled);
            }
        };

        window.addEventListener('scroll', handleScroll);

        return () => {
            window.removeEventListener('scroll', handleScroll);
        };
    }, [scrolled]);

    const toggleMenu = () => {
        setMenuOpen(!menuOpen);
    };

    const toggleLanguage = () => {
        const newLanguage = i18n.language === 'en' ? 'ja' : 'en';
        i18n.changeLanguage(newLanguage);
    };

    const toggleDropdown = (menu) => {
        setDropdownOpen(dropdownOpen === menu ? '' : menu);
    };

    const handleMouseEnter = (item) => {
        setHoveredItem(item);
        if (item === 'courses' || item === 'about') {
            setDropdownOpen(item);
        }
    };

    const handleMouseLeave = () => {
        setHoveredItem(null);
        setDropdownOpen('');
    };

    const openModal = () => {
        setIsLoginModalOpen(true);
        if (menuOpen) {
            setMenuOpen(false);
        }
    };

    const closeModal = () => {
        setIsLoginModalOpen(false);
    };

    const isActiveLink = (path) => {
        return location.pathname === path || location.pathname.startsWith(path + '/');
    };

    const getCurrentLanguage = () => {
        return i18n.language === 'en' ? 'EN' : 'JP';
    };

    return (
        <>
            <header className={`fixed top-0 left-0 right-0 z-50 transition-all duration-500 ${
                scrolled 
                    ? 'bg-white/95 backdrop-blur-xl shadow-2xl border-b border-gray-200/20' 
                    : 'bg-gradient-to-r from-blue-900/90 via-purple-900/90 to-indigo-900/90 backdrop-blur-sm'
            }`}>
                <div className="container mx-auto px-4 lg:px-8">
                    <div className="flex items-center justify-between h-20">
                        {/* Logo */}
                        <Link to="/" className="group flex items-center space-x-3 relative">
                            <div className="relative overflow-hidden rounded-xl p-2 bg-gradient-to-br from-blue-500 to-purple-600 group-hover:from-purple-500 group-hover:to-pink-600 transition-all duration-500 transform group-hover:scale-110 group-hover:rotate-3">
                                <img 
                                    src={logoWhiteImage} 
                                    alt="Forum Information Academy" 
                                    className="h-10 w-auto filter brightness-0 invert transition-transform duration-500 group-hover:scale-110" 
                                />
                            </div>
                            <div className="hidden md:block">
                                <h1 className={`text-xl font-bold bg-gradient-to-r from-blue-400 to-purple-400 bg-clip-text text-transparent group-hover:from-purple-400 group-hover:to-pink-400 transition-all duration-500 ${
                                    scrolled ? 'text-gray-800' : ''
                                }`}>
                                    Forum Academy
                                </h1>
                                <p className={`text-xs ${scrolled ? 'text-gray-600' : 'text-blue-200'} transition-colors duration-500`}>
                                    Excellence in Education
                                </p>
                            </div>
                            <div className="absolute -inset-2 bg-gradient-to-r from-blue-500/20 to-purple-500/20 rounded-2xl opacity-0 group-hover:opacity-100 transition-opacity duration-500 blur-xl"></div>
                        </Link>

                        {/* Desktop Navigation */}
                        <nav className="hidden lg:flex items-center space-x-1">
                            {/* Programs Dropdown */}
                            <div 
                                className="relative group"
                                onMouseEnter={() => handleMouseEnter('courses')}
                                onMouseLeave={handleMouseLeave}
                            >
                                <button className={`flex items-center space-x-1 px-4 py-2 rounded-full transition-all duration-300 ${
                                    scrolled 
                                        ? 'text-gray-700 hover:text-blue-600 hover:bg-blue-50' 
                                        : 'text-white hover:text-blue-200 hover:bg-white/10'
                                } ${isActiveLink('/courses') ? 'bg-blue-600 text-white' : ''}`}>
                                    <span className="font-medium">{t('navigation.programs')}</span>
                                    <svg className={`w-4 h-4 transition-transform duration-300 ${dropdownOpen === 'courses' ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                                    </svg>
                                </button>

                                {/* Mega Menu */}
                                <div className={`absolute top-full left-0 mt-2 w-screen max-w-4xl bg-white rounded-2xl shadow-2xl border border-gray-200/20 overflow-hidden transition-all duration-500 transform ${
                                    dropdownOpen === 'courses' 
                                        ? 'opacity-100 translate-y-0 scale-100' 
                                        : 'opacity-0 translate-y-4 scale-95 pointer-events-none'
                                }`}>
                                    <div className="p-8">
                                        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                                            <div className="space-y-4">
                                                <h3 className="text-lg font-bold text-gray-800 flex items-center">
                                                    <span className="text-2xl mr-2">🚀</span>
                                                    {t('navigation.featuredPrograms')}
                                                </h3>
                                                <div className="space-y-2">
                                                    {[
                                                        { to: '/courses/web-development', icon: '💻', title: t('courses.webDevelopment'), desc: t('courses.webDevelopmentDesc') },
                                                        { to: '/courses/data-science', icon: '📊', title: t('courses.dataScience'), desc: t('courses.dataScienceDesc') },
                                                        { to: '/courses/cybersecurity', icon: '🔒', title: t('courses.cybersecurity'), desc: t('courses.cybersecurityDesc') }
                                                    ].map((course, index) => (
                                                        <Link 
                                                            key={index}
                                                            to={course.to} 
                                                            className="group block p-4 rounded-xl hover:bg-gradient-to-r hover:from-blue-50 hover:to-purple-50 transition-all duration-300 border border-transparent hover:border-blue-200"
                                                        >
                                                            <div className="flex items-start space-x-3">
                                                                <span className="text-2xl group-hover:scale-110 transition-transform duration-300">{course.icon}</span>
                                                                <div>
                                                                    <h4 className="font-semibold text-gray-800 group-hover:text-blue-600 transition-colors duration-300">{course.title}</h4>
                                                                    <p className="text-sm text-gray-600 mt-1">{course.desc}</p>
                                                                </div>
                                                            </div>
                                                        </Link>
                                                    ))}
                                                </div>
                                            </div>

                                            <div className="space-y-4">
                                                <h3 className="text-lg font-bold text-gray-800 flex items-center">
                                                    <span className="text-2xl mr-2">💡</span>
                                                    {t('navigation.morePrograms')}
                                                </h3>
                                                <div className="space-y-2">
                                                    {[
                                                        { to: '/courses/cloud-computing', icon: '☁️', title: t('courses.cloudComputing'), desc: t('courses.cloudComputingDesc') },
                                                        { to: '/courses/ai-ml', icon: '🤖', title: t('courses.aiMl'), desc: t('courses.aiMlDesc') }
                                                    ].map((course, index) => (
                                                        <Link 
                                                            key={index}
                                                            to={course.to} 
                                                            className="group block p-4 rounded-xl hover:bg-gradient-to-r hover:from-purple-50 hover:to-pink-50 transition-all duration-300 border border-transparent hover:border-purple-200"
                                                        >
                                                            <div className="flex items-start space-x-3">
                                                                <span className="text-2xl group-hover:scale-110 transition-transform duration-300">{course.icon}</span>
                                                                <div>
                                                                    <h4 className="font-semibold text-gray-800 group-hover:text-purple-600 transition-colors duration-300">{course.title}</h4>
                                                                    <p className="text-sm text-gray-600 mt-1">{course.desc}</p>
                                                                </div>
                                                            </div>
                                                        </Link>
                                                    ))}
                                                </div>
                                            </div>

                                            <div className="bg-gradient-to-br from-blue-500 to-purple-600 rounded-2xl p-6 text-white">
                                                <h3 className="text-lg font-bold mb-2 flex items-center">
                                                    <span className="text-2xl mr-2">🎓</span>
                                                    {t('navigation.startJourney')}
                                                </h3>
                                                <p className="text-blue-100 mb-4">{t('navigation.joinStudents')}</p>
                                                <Link 
                                                    to="/apply" 
                                                    className="inline-flex items-center px-4 py-2 bg-white text-blue-600 rounded-lg font-semibold hover:bg-blue-50 transform hover:scale-105 transition-all duration-300"
                                                >
                                                    {t('buttons.applyNow')}
                                                    <svg className="w-4 h-4 ml-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7l5 5m0 0l-5 5m5-5H6" />
                                                    </svg>
                                                </Link>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            {/* About Dropdown */}
                            <div 
                                className="relative group"
                                onMouseEnter={() => handleMouseEnter('about')}
                                onMouseLeave={handleMouseLeave}
                            >
                                <button className={`flex items-center space-x-1 px-4 py-2 rounded-full transition-all duration-300 ${
                                    scrolled 
                                        ? 'text-gray-700 hover:text-blue-600 hover:bg-blue-50' 
                                        : 'text-white hover:text-blue-200 hover:bg-white/10'
                                } ${isActiveLink('/about') ? 'bg-blue-600 text-white' : ''}`}>
                                    <span className="font-medium">{t('navigation.about')}</span>
                                    <svg className={`w-4 h-4 transition-transform duration-300 ${dropdownOpen === 'about' ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                                    </svg>
                                </button>

                                <div className={`absolute top-full left-0 mt-2 w-80 bg-white rounded-2xl shadow-2xl border border-gray-200/20 overflow-hidden transition-all duration-500 transform ${
                                    dropdownOpen === 'about' 
                                        ? 'opacity-100 translate-y-0 scale-100' 
                                        : 'opacity-0 translate-y-4 scale-95 pointer-events-none'
                                }`}>
                                    <div className="p-6 space-y-2">
                                        {[
                                            { to: '/about', icon: 'ℹ️', title: t('navigation.aboutUs') },
                                            { to: '/team', icon: '👥', title: t('navigation.ourTeam') },
                                            { to: '/partners', icon: '🤝', title: t('navigation.industryPartners') },
                                            { to: '/testimonials', icon: '⭐', title: t('navigation.studentSuccess') }
                                        ].map((item, index) => (
                                            <Link 
                                                key={index}
                                                to={item.to} 
                                                className="group flex items-center space-x-3 p-3 rounded-xl hover:bg-gradient-to-r hover:from-blue-50 hover:to-purple-50 transition-all duration-300"
                                            >
                                                <span className="text-xl group-hover:scale-110 transition-transform duration-300">{item.icon}</span>
                                                <span className="font-medium text-gray-700 group-hover:text-blue-600 transition-colors duration-300">{item.title}</span>
                                            </Link>
                                        ))}
                                    </div>
                                </div>
                            </div>

                            {/* Other Navigation Items */}
                            {[
                                { to: '/news', title: t('navigation.newsEvents') },
                                { to: '/career-services', title: t('navigation.careerServices') },
                                { to: '/contact', title: t('navigation.contact') }
                            ].map((item, index) => (
                                <Link 
                                    key={index}
                                    to={item.to} 
                                    className={`px-4 py-2 rounded-full font-medium transition-all duration-300 relative overflow-hidden group ${
                                        scrolled 
                                            ? 'text-gray-700 hover:text-blue-600 hover:bg-blue-50' 
                                            : 'text-white hover:text-blue-200 hover:bg-white/10'
                                    } ${isActiveLink(item.to) ? 'bg-blue-600 text-white' : ''}`}
                                >
                                    <span className="relative z-10">{item.title}</span>
                                    <div className="absolute inset-0 bg-gradient-to-r from-blue-500 to-purple-500 transform scale-x-0 group-hover:scale-x-100 transition-transform duration-300 origin-left opacity-20"></div>
                                </Link>
                            ))}
                        </nav>

                        {/* Actions */}
                        <div className="flex items-center space-x-4">
                            {/* Language Selector */}
                            <button 
                                onClick={toggleLanguage}
                                className={`hidden md:flex items-center space-x-2 px-3 py-2 rounded-full transition-all duration-300 group ${
                                    scrolled 
                                        ? 'text-gray-700 hover:text-blue-600 hover:bg-blue-50' 
                                        : 'text-white hover:text-blue-200 hover:bg-white/10'
                                }`}
                            >
                                <svg className="w-5 h-5 group-hover:scale-110 transition-transform duration-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 5h12M9 3v2m1.048 9.5A18.022 18.022 0 016.412 9m6.088 9h7M11 21l5-10 5 10M12.751 5C11.783 10.77 8.07 15.61 3 18.129" />
                                </svg>
                                <span className="font-medium">{getCurrentLanguage()}</span>
                            </button>

                            {/* Login Button */}
                            <button 
                                onClick={onLoginClick}
                                className={`hidden md:flex items-center space-x-2 px-4 py-2 rounded-full font-medium transition-all duration-300 group ${
                                    scrolled 
                                        ? 'text-gray-700 hover:text-blue-600 hover:bg-blue-50 border border-gray-300 hover:border-blue-300' 
                                        : 'text-white hover:text-blue-200 border border-white/30 hover:bg-white/10'
                                }`}
                            >
                                <svg className="w-5 h-5 group-hover:scale-110 transition-transform duration-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                                </svg>
                                <span>{t('buttons.login')}</span>
                            </button>

                            {/* Apply Button */}
                            <Link 
                                to="/apply" 
                                className="bg-gradient-to-r from-blue-500 to-purple-600 hover:from-purple-500 hover:to-pink-600 text-white px-6 py-2 rounded-full font-semibold transition-all duration-300 transform hover:scale-105 hover:shadow-lg flex items-center space-x-2 group"
                            >
                                <span>{t('buttons.applyNow')}</span>
                                <svg className="w-4 h-4 group-hover:translate-x-1 transition-transform duration-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7l5 5m0 0l-5 5m5-5H6" />
                                </svg>
                            </Link>

                            {/* Mobile Menu Button */}
                            <button 
                                onClick={toggleMenu}
