                                </button>
                                <button onClick={onLoginClick} className="block w-full text-left py-2 text-white hover:text-blue-200 transition-colors duration-300">
                                    {t('buttons.login')}
                                </button>
                                <Link to="/apply" className="block py-2 bg-gradient-to-r from-blue-500 to-purple-600 text-white text-center rounded-lg font-semibold">
                                    {t('buttons.applyNow')}
                                </Link>
                            </div>
                        </div>
                    </div>
                </div>
            </header>

            <LoginModal 
                isOpen={isLoginModalOpen} 
                onClose={closeModal} 
            />
        </>
    );
};

export default Header;
